#!/usr/bin/env python3
"""Generate all mythological character JSON files for the character database.

This script contains embedded character data for 300+ characters from 
Ramayana and Mahabharata, and writes them as individual JSON files.

Usage:
    python data/characters/generate_all_characters.py
"""

import json
import os
import sys

BASE_DIR = os.path.dirname(os.path.abspath(__file__))
PROJECT_ROOT = os.path.dirname(os.path.dirname(BASE_DIR))

def write_character(subpath, data):
    """Write a character JSON file."""
    filepath = os.path.join(BASE_DIR, subpath)
    os.makedirs(os.path.dirname(filepath), exist_ok=True)
    with open(filepath, "w", encoding="utf-8") as f:
        json.dump(data, f, indent=4, ensure_ascii=False)
    return filepath

def build_char(key, char_id, name, aliases, epic, role, gender, ethnicity, 
               family, divine_origin, tags, timelines):
    """Build a standardized character dict."""
    return {
        key: {
            "metadata": {
                "character_id": char_id,
                "name": name,
                "aliases": aliases,
                "epic": epic,
                "primary_role": role,
                "gender": gender,
                "ethnicity_cultural_context": ethnicity,
                "family_relations": family,
                "divine_origin": divine_origin,
                "tags": tags
            },
            "timelines": timelines
        }
    }

def tl(stage, age, context, skin, height, build, face, hair, marks,
       clothing, jewelry, weapons, tone, pitch, speech, emotion,
       vis_prompt, aud_prompt):
    """Build a timeline entry."""
    return {
        "timeline_stage": stage,
        "age_approximation": age,
        "context_description": context,
        "physical_appearance": {
            "skin_tone": skin,
            "height": height,
            "build": build,
            "facial_features": face,
            "hair": hair,
            "distinguishing_marks": marks
        },
        "wardrobe_and_adornments": {
            "clothing": clothing,
            "jewelry": jewelry,
            "weapons_carried": weapons
        },
        "audio_and_voice_characteristics": {
            "tone": tone,
            "pitch": pitch,
            "speech_style": speech,
            "emotional_baseline": emotion
        },
        "cinematic_generation_prompts": {
            "visual_prompt": vis_prompt,
            "audio_prompt": aud_prompt
        }
    }

