def generate_all():
    """Generate all character files."""
    count = 0
    
    all_characters = []
    all_characters.extend(RAMAYANA_CORE)
    all_characters.extend(RAMAYANA_COURT)
    all_characters.extend(RAMAYANA_VANARA)
    all_characters.extend(RAMAYANA_RAKSHASA)
    all_characters.extend(RAMAYANA_SAGES)
    all_characters.extend(RAMAYANA_MINOR)

    for subpath, data in all_characters:
        filepath = write_character(subpath, data)
        # Extract character name for logging
        key = list(data.keys())[0]
        name = data[key]["metadata"]["name"]
        char_id = data[key]["metadata"]["character_id"]
        print(f"  ✓ {char_id} — {name} → {os.path.basename(filepath)}")
        count += 1

    print(f"\n{'='*60}")
    print(f"Generated {count} Ramayana character files")
    print(f"{'='*60}")
    return count


if __name__ == "__main__":
    print("=" * 60)
    print("Generating Mythological Character Database — Ramayana")
    print("=" * 60)
    total = generate_all()
    print(f"\nTotal characters generated: {total}")
